#!/usr/bin/env python3
import sys
import os

install_dir = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
src_dir = os.path.join(install_dir, "src")
sys.path.insert(0, src_dir)

from ibxcli.cli.main import cli

if __name__ == "__main__":
    cli()
ENTRYEOF

